parameters.jsCode:
const timeZone = 'America/New_York';
const today = new Date().toLocaleDateString('en-US', { 
  weekday: 'long', 
  timeZone 
});

const rows = $input.all();

const todayRows = rows.filter(item => {
  const r = item.json;
  const dayMatch = r['Day-week']?.trim().toLowerCase() === today.toLowerCase();
  const status = (r.Status || '').trim().toLowerCase();
  const isPending = status === 'pending' || status === '';
  return dayMatch && isPending;
});

if (todayRows.length === 0) {
  return []; 
}

return todayRows;

const item = $input.first().json;
const designInfo = $('Get Canva Design Info').item.json.design;
const pagesInfo = $('Get Canva Pages Info').item.json.items || [];

// 1. CONTEO REAL DE PÁGINAS
const pageCount = pagesInfo.length || designInfo.page_count || 1;

// 2. DIMENSIONES REALES (Usamos la primera página del diseño)
const firstPage = pagesInfo[0] || {};
const width = firstPage.dimensions?.width || designInfo.thumbnail?.width || 1080;
const height = firstPage.dimensions?.height || designInfo.thumbnail?.height || 1080;
const ratio = width / height;

// 3. DETECCIÓN TÉCNICA DE VIDEO
const isAnimated = designInfo.is_animated === true;
const supportsVideo = designInfo.urls?.view_url?.includes('.mp4') ?? false;
const isVideo = isAnimated || supportsVideo;

let format = 'post';
let mediatype = 'image';
let canvaExportFormat = 'png';
let canvaQuality = 'horizontal_1080p';

// LÓGICA DE CLASIFICACIÓN
if (ratio < 0.75) { 
  // STORY (Vertical: 1080x1920 es 0.56)
  format = 'stories';
  canvaQuality = 'vertical_1080p';
  if (isVideo || pageCount > 1) {
    mediatype = 'video';
    canvaExportFormat = 'mp4';
  }
} else if (pageCount > 1) {
  // CAROUSEL (Cuadrado/4:5 + Multipágina)
  format = 'carousel';
  mediatype = 'image';
  canvaExportFormat = 'png';
} else {
  // POST (Cuadrado/4:5 + 1 Página)
  format = 'post';
  if (isVideo) {
    mediatype = 'video';
    canvaExportFormat = 'mp4';
  }
}

return {
  json: {
    format,
    mediatype,
    getlate_media_type: mediatype,
    canvaExportFormat,
    canvaQuality,
    pages: pageCount,
    title: designInfo.title,
    debug: { isVideo, ratio, width, height, pageCount }
  }
};

const item = $input.first().json;

const cleanText = (text) => text?.replace(/\\\\n/g, ' ').replace(/\\n/g, ' ').trim() || '';
const cleanUrl = (url) => url?.replace(/\\\\n/g, '').replace(/\\n/g, '').trim() || '';

// Función para asegurar que el sitio web tenga https://
const formatWebsite = (url) => {
  if (!url) return '';
  let clean = url.trim();
  // Si empieza con www. o no tiene protocolo, añadir https://
  if (!clean.startsWith('http://') && !clean.startsWith('https://')) {
    return `https://${clean}`;
  }
  return clean;
};

return [{
  json: {
    Design_ID:   item.Design_ID   || '',
    Description: cleanText(item.Description),
    Hashtags:    item.Hashtags    || '',
    image_url:   cleanUrl(item.image_url),
    Image_url_2: cleanUrl(item.image_url_2),
    image_url_3: cleanUrl(item.image_url_3),
    image_url_4: cleanUrl(item.image_url_4),
    image_url_5: cleanUrl(item.image_url_5),
    image_url_6: cleanUrl(item.image_url_6),
    image_url_7: cleanUrl(item.image_url_7),
    format:      item.Format      || '',
    Status:      item.Status      || '',
    // Usamos Web_links que es el nombre que tienes en el workflow
    Web_links:   formatWebsite(item.Web_links || item.Website) 
  }
}];

